import{_ as a,o,c as l,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"121. Uniform Allowance","description":"","frontmatter":{"title":"121. Uniform Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/121-uniform-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/121-uniform-allowance.md"}'),n={name:"ebas/mental-health/health-professionals/allowances/121-uniform-allowance.md"};function r(s,e,i,h,c,m){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="_121-uniform-allowance" tabindex="-1">121. Uniform Allowance <a class="header-anchor" href="#_121-uniform-allowance" aria-label="Permalink to &quot;121. Uniform Allowance&quot;">​</a></h1><p><strong>121.1</strong> Where the Employer requires an Employee to wear any special clothing or uniform, the Employer must reimburse the Employee for the cost of purchasing such special clothing or uniform. The provisions of this clause do not apply where the special clothing or uniform is paid for by the Employer.</p><p><strong>121.2</strong> Notwithstanding clause 121.1 above, the Employer may, by agreement with the Employee, pay a uniform allowance at the daily or weekly rate set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> (whichever is the lesser amount in total) when the Employee is expected to provide their own uniforms or coats. When such Employee&#39;s uniforms or coats are not laundered by or at the expense of the Employer, the Employee shall be paid a laundry allowance at the daily or weekly rate set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> (whichever is the lesser amount in total).</p><p><strong>121.3</strong> The rounding provision does not apply to the calculation of this allowance.</p>',4)])])}const f=a(n,[["render",r]]);export{u as __pageData,f as default};
